// weatherApi.js

const API_KEY = process.env.REACT_APP_OPENWEATHER_API_KEY;

const getWeatherEmoji = (main) => {
  switch (main.toLowerCase()) {
    case "clear":
      return "☀️";
    case "clouds":
      return "☁️";
    case "rain":
      return "🌧️";
    case "thunderstorm":
      return "⛈️";
    case "snow":
      return "❄️";
    case "mist":
    case "fog":
    case "haze":
      return "🌫️";
    default:
      return "🌤️";
  }
};

export async function fetchCityWeather(cityName) {
  if (!API_KEY) {
    throw new Error(
      "Missing API key. Add REACT_APP_OPENWEATHER_API_KEY to your .env file."
    );
  }

  const currentRes = await fetch(
    `https://api.openweathermap.org/data/2.5/weather?q=${cityName}&appid=${API_KEY}&units=metric`
  );

  if (!currentRes.ok) {
    throw new Error("City not found");
  }

  const currentData = await currentRes.json();

  const forecastRes = await fetch(
    `https://api.openweathermap.org/data/2.5/forecast?q=${cityName}&appid=${API_KEY}&units=metric`
  );

  const forecastData = await forecastRes.json();

  const dailyForecast = forecastData.list
    .filter((item) => item.dt_txt.includes("12:00:00"))
    .slice(0, 5)
    .map((item) => ({
      day: new Date(item.dt_txt).toLocaleDateString("en-US", {
        weekday: "short",
      }),
      date: new Date(item.dt_txt).toLocaleDateString("en-US", {
        month: "short",
        day: "numeric",
      }),
      high: Math.round(item.main.temp_max),
      low: Math.round(item.main.temp_min),
      icon: getWeatherEmoji(item.weather[0].main),
      desc: item.weather[0].description,
    }));

  return {
    name: currentData.name,
    country: currentData.sys.country,

    current: {
      temp: Math.round(currentData.main.temp),
      desc: currentData.weather[0].description,
      icon: getWeatherEmoji(currentData.weather[0].main),
      humidity: currentData.main.humidity,
      wind: Math.round(currentData.wind.speed * 3.6), // km/h
    },

    forecast: dailyForecast,
  };
}
